// Verify fetchWeather returns all fields needed for map indicators
async function testWeatherApiDataShape() {
  const result = await functions.call('fetchWeather', 41.39, 2.17);
  assert(result.ok === true, 'fetchWeather should succeed');

  const data = result.data;

  // Fields needed by updateMapIndicators — temperature badge
  assert(typeof data.current.temperature === 'number', 'Should have temperature for indicator badge');

  // Pressure badge with H/L annotation
  assert(typeof data.current.pressure === 'number', 'Should have pressure for indicator badge');
  assert(data.current.pressure > 900 && data.current.pressure < 1100, 'Pressure should be in valid hPa range');

  // Wind badge with direction arrow
  assert(typeof data.current.windSpeed === 'number', 'Should have windSpeed for wind indicator');
  assert(typeof data.current.windDirection === 'number', 'Should have windDirection for wind arrow');

  // Wave height for wave badge (may be null in some areas)
  assert(data.current.waveHeight === null || typeof data.current.waveHeight === 'number',
    'waveHeight should be number or null');

  // Hourly data for timeline scrubbing — all fields present
  assert(data.hourly.length >= 24, 'Should have at least 24 hourly entries');
  var h = data.hourly[0];
  assert(typeof h.temperature === 'number', 'Hourly should have temperature');
  assert(typeof h.pressure === 'number', 'Hourly should have pressure');
  assert(typeof h.windSpeed === 'number', 'Hourly should have windSpeed');
  assert(typeof h.windDirection === 'number', 'Hourly should have windDirection');
}
